code = """import json, pandas as pd

qlis = pd.DataFrame(var_call_oGtSKHebx5RnAUc6FeNMXPye)
for c in ['Quantity']:
    qlis[c] = pd.to_numeric(qlis[c], errors='coerce')

# Load KAs
ka_path = var_call_7b41RbFwHX6Rf8tSijJVQhVC
with open(ka_path,'r',encoding='utf-8') as f:
    kas = json.load(f)

# Find Product Quantity Limits article
ka_qty_id = None
for r in kas:
    if 'product quantity limits' in (r.get('title','').lower() if isinstance(r.get('title',''),str) else ''):
        ka_qty_id = r['id']
        ka_qty = r
        break

# parse limits from faq_answer__c (simple)
text = ka_qty.get('faq_answer__c','') if ka_qty_id else ''
limits = {}
for line in text.splitlines():
    if '- Customers can purchase up to' in line or '- A maximum of' in line or 'Each order is limited to' in line or 'can order up to' in line or 'limited to' in line or 'available in quantities of up to' in line or 'order a maximum of' in line:
        # extract product name before '-' and first integer in line
        parts = line.split('-')
        if len(parts)>=2:
            name = parts[0].strip(' *')
            import re
            m = re.search(r'(\d+)', line)
            if m:
                limits[name] = int(m.group(1))

# Load product names for quote line items from Product2 file
prod_path = var_call_ZC6tEuGz84Rxyza4xLc53Zv0
with open(prod_path,'r',encoding='utf-8') as f:
    prods = json.load(f)
prod_df = pd.DataFrame(prods)
prod_df['Id_norm'] = prod_df['Id'].astype(str).str.replace('#','', regex=False).str.strip()
prod_df['Name_norm'] = prod_df['Name'].astype(str).str.strip()

qlis['Product2Id_norm'] = qlis['Product2Id'].astype(str).str.replace('#','', regex=False).str.strip()
qlp = qlis.merge(prod_df[['Id_norm','Name_norm']], left_on='Product2Id_norm', right_on='Id_norm', how='left')

violations = []
for _, row in qlp.iterrows():
    pname = row['Name_norm']
    qty = row['Quantity']
    if isinstance(pname,str) and pname in limits and pd.notna(qty):
        if qty > limits[pname]:
            violations.append({'Product':pname,'Quantity':float(qty),'Limit':limits[pname]})

result = {'knowledge_article_id': ka_qty_id if violations else None, 'violations_found': len(violations), 'violations': violations[:5]}
print('__RESULT__:')
print(json.dumps(result))"""

